        function atributos($id_producto, $datos) {
            $code = '';
            if ($datos['atributos']['error'] == false) {
//                var_dump($id_producto);
//                var_dump($datos['atributos']['depurar']['ids']);

                if (in_array($id_producto, $datos['atributos']['depurar']['ids'])) {

                    foreach ($datos['atributos']['depurar']['atributos'][$id_producto] as $key => $value) {
//                        var_dump($key);
//                        var_dump($value);
                        if ($key == "Color") {
                            $code .= '<tr>
                                                    <td style="text-align: right;">
                                                        <strong style="position: relative;">
                                                            Color:
                                                        </strong>
                                                    </td>
                                                    <td style="text-align: left;">
                                                        <span style="display: inline-block;width: 35px;height: 35px;border-radius: 100%;background-color: ' . $value[0]['valor_atributo'] . ';"></span>
                                                    </td>
                                                </tr>';
                        } elseif ($key == "Medidas") {
//                            var_dump($value);
                            $codeM = '';
                            foreach ($value as $keyM => $valueM) {
                                $codeM .= '<p>
                                                            ' . $valueM['valor_atributo'] . ' ' . $valueM['unidad_medida_atributo'] . ' ' . $valueM['descripcion_atributo'] . '
                                                        </p>';
                            }
                            $code .= '<tr>
                                                    <td style="text-align: right;">
                                                        <strong>
                                                            Medidas:
                                                        </strong>
                                                    </td>
                                                    <td style="text-align: left;">
                                                        ' . $codeM . '
                                                    </td>
                                                </tr>';
                        } else {
                            $code .= '<tr>
                                                    <td style="text-align: right;">
                                                        <strong style="position: relative;">
                                                            ' . $key . ':
                                                        </strong>
                                                    </td>
                                                    <td style="text-align: left;">
                                                        ' . $value[0]['valor_atributo'] . ' ' . $value[0]['unidad_medida_atributo'] . ' ' . $value[0]['descripcion_atributo'] . '
                                                    </td>
                                                </tr>';
                        }
                    }
                }
            }
            return $code;
        }

        function variantes($id_producto, $datos) {
            $code = '';
//            var_dump($datos['variantes']);
            if ($datos['variantes']['error'] == false) {
//                var_dump($id_producto);
//                var_dump($datos['atributos']['depurar']['ids']);
//                var_dump($datos['variantes']['depurar']);
//                var_dump(in_array($id_producto, $datos['variantes']['depurar']['ids_principales']));
                if (in_array($id_producto, $datos['variantes']['depurar']['ids_principales'])) {
//                    var_dump($datos['variantes']['depurar']['variantes']);
                    foreach ($datos['variantes']['depurar']['variantes'][$id_producto] as $key => $value) {
//                        var_dump($key);
//                        var_dump($value);
                        $path_portada_clasificacion = $value['url_imagen'];
                        $type_portada_clasificacion = pathinfo($path_portada_clasificacion, PATHINFO_EXTENSION);
                        $data_portada_clasificacion = file_get_contents($path_portada_clasificacion);
//                var_dump($data_portada_categoria);
                        $base64_portada_clasificacion = 'data:image/' . $type_portada_clasificacion . ';base64,' . base64_encode($data_portada_clasificacion);
                        $code .= '
                                                    <div style="width: fit-content;border-radius: 2px;border:2px solid gray;display: inline-block;margin-right: 1px;">
                                                            <img src="' . $base64_portada_clasificacion . '" width="35" height="35">
                                                        </div>
                                                   
                                               ';
                    }
                    $code = '<tr>
                                                    <td style="text-align: left;" colspan="2">
                                                        ' . $code . '
                                                    </td>
                                                </tr>';
                }
            }
            return $code;
        }

